DO $$ BEGIN CREATE TYPE "FlowStatus" AS ENUM ('active','paused','error','draft'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "TriggerType" AS ENUM ('tire_alert_level','tire_depth_threshold','scheduled_cron','tire_eol_approaching','inspection_completed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "ActionType" AS ENUM ('send_email','send_whatsapp','create_calendar_event','make_phone_call','create_notification'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE "IntegrationType" AS ENUM ('google_calendar','twilio_phone'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
CREATE TABLE IF NOT EXISTS "automation_flows" ("id" TEXT NOT NULL DEFAULT gen_random_uuid(),"companyId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"status" "FlowStatus" NOT NULL DEFAULT 'active',"createdBy" TEXT NOT NULL,"triggerType" "TriggerType" NOT NULL,"triggerConfig" JSONB NOT NULL,"actionType" "ActionType" NOT NULL,"actionConfig" JSONB NOT NULL,"lastRunAt" TIMESTAMP(3),"runCount" INTEGER NOT NULL DEFAULT 0,"errorCount" INTEGER NOT NULL DEFAULT 0,"lastError" TEXT,"cooldownMinutes" INTEGER NOT NULL DEFAULT 60,"maxRunsPerDay" INTEGER NOT NULL DEFAULT 100,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "automation_flows_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "flow_runs" ("id" TEXT NOT NULL DEFAULT gen_random_uuid(),"flowId" TEXT NOT NULL,"triggerPayload" JSONB,"success" BOOLEAN NOT NULL,"output" JSONB,"error" TEXT,"durationMs" INTEGER,"entityType" TEXT,"entityId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "flow_runs_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "integration_connections" ("id" TEXT NOT NULL DEFAULT gen_random_uuid(),"companyId" TEXT NOT NULL,"type" "IntegrationType" NOT NULL,"accessToken" TEXT,"refreshToken" TEXT,"tokenExpiresAt" TIMESTAMP(3),"accountEmail" TEXT,"accountName" TEXT,"scopes" TEXT[] DEFAULT ARRAY[]::TEXT[],"isActive" BOOLEAN NOT NULL DEFAULT true,"lastUsedAt" TIMESTAMP(3),"lastError" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "integration_connections_pkey" PRIMARY KEY ("id"));
ALTER TABLE "automation_flows" ADD CONSTRAINT "automation_flows_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "flow_runs" ADD CONSTRAINT "flow_runs_flowId_fkey" FOREIGN KEY ("flowId") REFERENCES "automation_flows"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "integration_connections" ADD CONSTRAINT "integration_connections_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE INDEX IF NOT EXISTS "automation_flows_companyId_status_idx" ON "automation_flows"("companyId","status");
CREATE INDEX IF NOT EXISTS "automation_flows_triggerType_status_idx" ON "automation_flows"("triggerType","status");
CREATE INDEX IF NOT EXISTS "flow_runs_flowId_createdAt_idx" ON "flow_runs"("flowId","createdAt");
CREATE INDEX IF NOT EXISTS "flow_runs_flowId_entityId_createdAt_idx" ON "flow_runs"("flowId","entityId","createdAt");
CREATE UNIQUE INDEX IF NOT EXISTS "integration_connections_companyId_type_key" ON "integration_connections"("companyId","type");
CREATE INDEX IF NOT EXISTS "integration_connections_companyId_idx" ON "integration_connections"("companyId");
